@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel">
            <div class="infinite-scroll-loading">
                <svg class="spinner" viewBox="0 0 50 50">
                    <circle cx="25" cy="25" r="20" fill="none" stroke="currentColor" stroke-width="4" stroke-dasharray="90,150" stroke-linecap="round" />
                </svg>
                <span>Loading...</span>
            </div>
        </div>
    }
</div>

<style>
    .infinite-scroll-container {
        overflow-y: auto;
        max-height: 100%;
    }

    .infinite-scroll-sentinel {
        display: flex;
        justify-content: center;
        padding: 1rem;
    }

    .infinite-scroll-loading {
        display: flex;
        align-items: center;
        gap: 0.5rem;
        color: #666;
    }

    .spinner {
        width: 1.5rem;
        height: 1.5rem;
        animation: spin 1s linear infinite;
    }

    @@keyframes spin {
        100% { transform: rotate(360deg); }
    }
</style>

using Microsoft.AspNetCore.Components;
using Microsoft.JSInterop;

namespace sv_1de22b1ed1a644f79c7b9fe5bd4fdea4.Components;

public partial class InfiniteScrollList<TItem> : IAsyncDisposable
{
    private ElementReference _sentinelRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _observer;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/InfiniteScrollList.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
        }

        if (HasMore && _module is not null)
        {
            // Re-observe on every render so the sentinel is always tracked
            // (it may have been removed/re-added to the DOM).
            if (_observer is not null)
            {
                await _observer.InvokeVoidAsync("disconnect");
                await _observer.DisposeAsync();
            }

            _observer = await _module.InvokeAsync<IJSObjectReference>(
                "observe", _sentinelRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnIntersecting()
    {
        if (_isLoading || !HasMore)
            return;

        _isLoading = true;
        await OnLoadMore.InvokeAsync();
        _isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_observer is not null)
        {
            await _observer.InvokeVoidAsync("disconnect");
            await _observer.DisposeAsync();
        }

        if (_module is not null)
            await _module.DisposeAsync();

        _dotNetRef?.Dispose();
    }
}

export function observe(sentinelElement, dotNetRef) {
    const observer = new IntersectionObserver((entries) => {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                dotNetRef.invokeMethodAsync('OnIntersecting');
            }
        }
    }, {
        rootMargin: '0px 0px 128px 0px' // trigger 128px before the sentinel is visible
    });

    observer.observe(sentinelElement);
    return observer;
}

